-- Notification templates for the job offers and job applications modules
	 -- Job offer - Notification - Expired closing date and not closed status
	('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Notification - Offer with expired closing date and not closed status', 'Template to notify the responsible user that the offer has an application closing date of yesterday and is not in closed status or similar.', 'Review job offer: application deadline passed - $stic_job_offers_name', 'Dear $stic_job_offers_assigned_user_name,\r\n\r\nThe job offer $stic_job_offers_name has an expired application closing date (yesterday) and is currently in status $stic_job_offers_status.\r\n\r\nPlease review the offer and update its status if appropriate: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Dear $stic_job_offers_assigned_user_name,</p>\n<p>The job offer <strong>$stic_job_offers_name</strong> has an expired application closing date (yesterday) and is currently in status <strong>$stic_job_offers_status</strong>.</p>\n<p>Please <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">review the offer</a> and update its status if appropriate.</p>', 0, '1', 0, 'notification'),
	-- Accepted application - Assigned user 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0001', NOW(), NOW(), '1', '1', NULL, 'Accepted application - Assigned user ', 'Notifies the assigned user when an application changes to Accepted, with a CRM link.', 'Accepted application: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_assigned_user_name,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Accepted status.\r\n\r\nYou can review it in the CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Dear $stic_job_applications_assigned_user_name,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Accepted</strong> status.</p><p>You can review it in the CRM: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Open application in CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Accepted application - Candidate 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0002', NOW(), NOW(), '1', '1', NULL, 'Accepted application - Candidate ', 'Notifies the candidate when their application changes to Accepted, with a private area link.', 'Your application has been accepted: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nWe are pleased to inform you that your application for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Accepted status.\r\n\r\nYou can view the details in your private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_stic_job_applications_contacts_name:</p><p>We are pleased to inform you that your application for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Accepted</strong> status.</p><p>You can view the details in your private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
	-- Accepted application - Organization 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0003', NOW(), NOW(), '1', '1', NULL, 'Accepted application - Organization ', 'Notifies the organization when an application changes to Accepted, with a private area link.', 'Accepted application in offer: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_account,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Accepted status.\r\n\r\nYou can view it in the private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_account,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Accepted</strong> status.</p><p>You can view it in the private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
	-- Rejected or closed application - Assigned user 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0004', NOW(), NOW(), '1', '1', NULL, 'Rejected/closed application - Assigned user ', 'Notifies the assigned user when an application changes to Rejected or closed, with a CRM link.', 'Rejected or closed application: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_assigned_user_name,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Rejected or closed status.\r\n\r\nYou can access details at: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Dear $stic_job_applications_assigned_user_name,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Rejected or closed</strong> status.</p><p>You can access details at: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Open application in CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Rejected or closed application - Candidate 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0005', NOW(), NOW(), '1', '1', NULL, 'Rejected/closed application - Candidate ', 'Notifies the candidate when their application changes to Rejected or closed, with a private area link.', 'Update on your application: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nYour application for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Rejected or closed status.\r\n\r\nYou can view the details in your private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_stic_job_applications_contacts_name:</p><p>Your application for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Rejected or closed</strong> status.</p><p>You can view the details in your private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
	-- Rejected or closed application - Organization 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0006', NOW(), NOW(), '1', '1', NULL, 'Rejected/closed application - Organization ', 'Notifies the organization when an application changes to Rejected or closed, with a private area link.', 'Rejected or closed application in offer: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_account,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Rejected or closed status.\r\n\r\nYou can view it in the private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_account,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Rejected or closed</strong> status.</p><p>You can view it in the private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
	-- Other application statuses - Assigned user 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0007', NOW(), NOW(), '1', '1', NULL, 'Other application statuses - Assigned user ', 'Notifies the assigned user when an application changes to other statuses, with a CRM link.', 'Application status changed: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_assigned_user_name,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to status $stic_job_applications_status.\r\n\r\nYou can access details at: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Dear $stic_job_applications_assigned_user_name,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to status <strong>$stic_job_applications_status</strong>.</p><p>You can access details at: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Open application in CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Other application statuses - Candidate 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0008', NOW(), NOW(), '1', '1', NULL, 'Other application statuses - Candidate ', 'Notifies the candidate when their application changes to other statuses, with a private area link.', 'Your application status changed: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nYour application for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to status $stic_job_applications_status.\r\n\r\nYou can view the details in your private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_stic_job_applications_contacts_name:</p><p>Your application for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to status <strong>$stic_job_applications_status</strong>.</p><p>You can view the details in your private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
	-- Other application statuses - Organization 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0009', NOW(), NOW(), '1', '1', NULL, 'Other application statuses - Organization ', 'Notifies the organization when an application changes to other statuses, with a private area link.', 'Application status changed in offer: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_account,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to status $stic_job_applications_status.\r\n\r\nYou can view it in the private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_account,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to status <strong>$stic_job_applications_status</strong>.</p><p>You can view it in the private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
	-- Offer - Status change - Assigned user 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0010', NOW(), NOW(), '1', '1', NULL, 'Offer status change - Assigned user ', 'Notifies the assigned user when an offer status changes, with a CRM link.', 'Offer status changed: $stic_job_offers_name', 'Dear $stic_job_offers_assigned_user_name,\r\n\r\nThe offer $stic_job_offers_name has changed to status $stic_job_offers_status.\r\n\r\nYou can access details at: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Dear $stic_job_offers_assigned_user_name,</p><p>The offer <strong>$stic_job_offers_name</strong> has changed to status <strong>$stic_job_offers_status</strong>.</p><p>You can access details at: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Open offer in CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Offer - Status change - Candidates 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0011', NOW(), NOW(), '1', '1', NULL, 'Offer status change - Candidates ', 'Notifies candidates of an offer status change, with a private area link.', 'Offer update: $stic_job_offers_name', 'Dear,\r\n\r\nThe offer $stic_job_offers_name has changed to status $stic_job_offers_status.\r\n\r\nYou can view the offer in the private area: $portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id', '<p>Dear,</p><p>The offer <strong>$stic_job_offers_name</strong> has changed to status <strong>$stic_job_offers_status</strong>.</p><p>You can view the offer in the private area: <a href="$portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id">View offer in private area</a>.</p>', 0, '1', 0, 'notification'),
	-- Offer - Status change - Organization 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0012', NOW(), NOW(), '1', '1', NULL, 'Offer status change - Organization ', 'Notifies the organization of an offer status change, with a private area link.', 'Offer status changed: $stic_job_offers_name', 'Dear $stic_job_offers_stic_job_offers_accounts_name,\r\n\r\nThe offer $stic_job_offers_name has changed to status $stic_job_offers_status.\r\n\r\nYou can review it in the private area: $portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id', '<p>Dear $stic_job_offers_stic_job_offers_accounts_name,</p><p>The offer <strong>$stic_job_offers_name</strong> has changed to status <strong>$stic_job_offers_status</strong>.</p><p>You can review it in the private area: <a href="$portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id">View offer in private area</a>.</p>', 0, '1', 0, 'notification'),
	-- Private Area - Access credentials - Contact
	('6e6f5a91-2cb9-4f42-bf26-0a13b2f1c101', NOW(), NOW(), '1', '1', NULL, 'Private Area - Access credentials (Contact)', 'Initial template to send Private Area credentials to Contacts when access is enabled', 'Your Private Area access credentials', 'Hello $contacts_name,\r\n\r\nYour access to the Private Area has been enabled.\r\n\r\nUsername: $contacts_stic_pa_username_c\r\nPassword: $contacts_stic_pa_password_c\r\n\r\nAccess from: $portal_address\r\n\r\nIf you did not request this access, please contact the organization.', '<p>Hello $contacts_name,</p><p>Your access to the Private Area has been enabled.</p><p><strong>Username:</strong> $contacts_stic_pa_username_c<br><strong>Password:</strong> $contacts_stic_pa_password_c</p><p>Access from: <a href="$portal_address">$portal_address</a></p><p>If you did not request this access, please contact the organization.</p>', 0, '1', 0, 'notification'),
	-- Private Area - Access credentials - Account
	('6e6f5a91-2cb9-4f42-bf26-0a13b2f1c102', NOW(), NOW(), '1', '1', NULL, 'Private Area - Access credentials (Account)', 'Initial template to send Private Area credentials to Accounts when access is enabled', 'Private Area access credentials', 'Hello $accounts_name,\r\n\r\nYour access to the Private Area has been enabled.\r\n\r\nUsername: $accounts_stic_pa_username_c\r\nPassword: $accounts_stic_pa_password_c\r\n\r\nAccess from: $portal_address\r\n\r\nIf you did not request this access, please contact the organization.', '<p>Hello $accounts_name,</p><p>Your access to the Private Area has been enabled.</p><p><strong>Username:</strong> $accounts_stic_pa_username_c<br><strong>Password:</strong> $accounts_stic_pa_password_c</p><p>Access from: <a href="$portal_address">$portal_address</a></p><p>If you did not request this access, please contact the organization.</p>', 0, '1', 0, 'notification');

